import React, { useState } from 'react';
import { db } from '../firebase'; 
import { collection, query, where, getDocs } from 'firebase/firestore';
import { ArrowRight, AlertCircle } from 'lucide-react';

function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleAuth = async (e) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const formattedUsername = username.trim().toLowerCase();
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("username", "==", formattedUsername), where("password", "==", password));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        const userData = querySnapshot.docs[0].data();
        localStorage.setItem('user_info', JSON.stringify({ 
          name: userData.fullName || formattedUsername.toUpperCase(), 
          role: userData.role || 'student', 
          username: userData.username || formattedUsername
        }));

        const userRole = (userData.role || "").toLowerCase();
        if (userRole === 'admin' || formattedUsername === 'admin') {
          onLogin('admin');
        } else {
          onLogin('student');
        }
      } else {
        setError("Invalid username or password.");
      }
    } catch (err) {
      console.error("Auth Error:", err);
      setError("Failed to connect to the database.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen font-sans bg-gray-50">
      
      {/* LEFT SIDE: Brand & Gradient (Your Original Structure) */}
      <div className="hidden md:flex flex-col justify-center items-center w-1/2 bg-gradient-to-br from-[#4b1d82] via-[#5c24a1] to-[#3a156b] relative overflow-hidden p-12">
        {/* Soft abstract blobs for polish */}
        <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-purple-500/30 blur-[80px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-indigo-500/30 blur-[80px] rounded-full"></div>
        
        <div className="relative z-10 text-center text-white">
          <h1 className="text-6xl font-extrabold tracking-tight mb-4 drop-shadow-lg">CampusCanvas</h1>
          <p className="text-xl text-purple-200 font-medium">Institutional Project Repository</p>
          <div className="mt-12 text-sm text-purple-300/80 font-medium tracking-widest uppercase">
            Secure Access Portal • University
          </div>
        </div>
      </div>

      {/* RIGHT SIDE: Clean White Login Form */}
      <div className="flex flex-col justify-center items-center w-full md:w-1/2 p-6">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.08)] border border-gray-100">
          
          <div className="text-center mb-10">
            <h2 className="text-3xl font-bold text-gray-900 mb-2">Welcome Back</h2>
            <p className="text-gray-500 text-sm">Please enter your credentials</p>
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 p-4 rounded-xl mb-6 text-sm font-medium flex items-center gap-2 border border-red-100">
              <AlertCircle className="w-5 h-5 shrink-0" /> {error}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-6">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Roll Number / ID</label>
              <input 
                type="text" 
                value={username} 
                onChange={(e) => setUsername(e.target.value)} 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 text-gray-900 outline-none focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all placeholder-gray-400 lowercase"
                placeholder="e.g. 23bsccs01"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Password</label>
              <input 
                type="password" 
                value={password} 
                onChange={(e) => setPassword(e.target.value)} 
                className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-3.5 text-gray-900 outline-none focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all placeholder-gray-400"
                placeholder="••••••••"
                required
              />
            </div>

            <button 
              type="submit" 
              disabled={isLoading}
              className={`w-full mt-4 py-4 rounded-xl font-bold text-lg flex justify-center items-center gap-2 transition-all ${isLoading ? 'bg-purple-400 text-white cursor-not-allowed' : 'bg-[#6a35ff] hover:bg-[#5b2ce0] text-white shadow-lg shadow-purple-500/30 hover:shadow-purple-500/50 hover:-translate-y-0.5'}`}
            >
              {isLoading ? 'Authenticating...' : <>Access Portal <ArrowRight className="w-5 h-5" /></>}
            </button>
          </form>

          <div className="mt-8 text-center text-xs text-gray-400 font-medium">
            Authorized Personnel Only.<br/>Contact Admin for access issues.
          </div>
        </div>
      </div>

    </div>
  );
}

export default Login;
